{"content":"use crate::api::*;
use std::sync::RwLock;

struct VectorData {
    id: u64,
    vector: Vec<f32>,
}

pub struct VectorDB {
    data: RwLock<Vec<VectorData>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        data.push(VectorData { id, vector });
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            data.push(VectorData { id, vector });
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();
        let mut candidates: Vec<SearchResult> = data.iter().map(|item| {
            let dist = crate::distance::l2_distance(&item.vector, vector);
            SearchResult { id: item.id, distance: dist }
        }).collect();

        // Sort by distance
        candidates.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));

        candidates.into_iter().take(top_k as usize).collect()
    }
}
