{"path":"src/db.rs","content":"use crate::api::*;
use std::sync::RwLock;

pub struct VectorDB {
    data: RwLock<VectorStorage>,
}

struct VectorStorage {
    ids: Vec<u64>,
    vectors: Vec<f32>,
    count: usize,
}

const DIM: usize = 128;

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(VectorStorage {
                ids: Vec::new(),
                vectors: Vec::new(),
                count: 0,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != DIM {
            panic!("Vector dimension mismatch");
        }
        let mut data = self.data.write().unwrap();
        data.ids.push(id);
        data.vectors.extend(vector);
        data.count += 1;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = vectors.len();
        data.ids.reserve(count);
        data.vectors.reserve(count * DIM);

        for (id, vector) in vectors {
            if vector.len() != DIM {
                continue; 
            }
            data.ids.push(id);
            data.vectors.extend(vector);
            data.count += 1;
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if vector.len() != DIM {
            return Vec::new();
        }

        let data = self.data.read().unwrap();
        let n = data.count;
        let k = top_k as usize;

        // Use a min-heap to keep top-k to avoid allocating full results vector
        // However, standard BinaryHeap is a max-heap. We can store (Reverse(FiniteF64), id). 
        // Or simpler: just use a vector and select_nth_unstable if N is huge. 
        // With 1M entries, allocating a Vec<(usize, f64)> of 1M size is ~16MB. Not too bad, but 
        // repeated 4x concurrently is 64MB/s of allocation.

        // Let's try to process in chunks to keep cache locality and potentially use Rayon for parallelism.
        // But the prompt says "4 dedicated cores available" and "using more than 4 threads will cause contention".
        // The server is already getting concurrent requests (concurrency=4).
        // So we should probably stick to single-threaded search per request, but optimize the scanning.

        // We can optimize the distance calculation by unrolling or blocking.
        // But let's first fix the allocation overhead.

        let mut scores: Vec<(usize, f64)> = Vec::with_capacity(n);

        // Raw pointer access to avoid slice bounds checks in the hot loop
        let vectors_ptr = data.vectors.as_ptr();

        // We can block this loop to keep 'vector' in L1/L2 cache
        // But 'vector' is small (128 floats = 512 bytes), so it stays in registers/L1 easily.
        // The bottleneck is reading 1M vectors from RAM.

        // Let's just do a plain loop but use raw pointers to be sure
        for i in 0..n {
            let dist = unsafe {
                // calculate offset
                let p = vectors_ptr.add(i * DIM);
                crate::distance::l2_distance(std::slice::from_raw_parts(p, DIM), vector)
            };
            scores.push((i, dist));
        }

        if k < scores.len() {
            scores.select_nth_unstable_by(k, |a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));
            scores.truncate(k);
        }

        scores.sort_unstable_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));

        scores.into_iter().map(|(idx, dist)| {
            SearchResult {
                id: data.ids[idx],
                distance: dist,
            }
        }).collect()
    }
}
