    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();
        let mut candidates: Vec<SearchResult> = data.iter().map(|item| {
            let dist = crate::distance::l2_distance(&item.vector, vector);
            SearchResult { id: item.id, distance: dist }
        }).collect();

        // Sort by distance
        candidates.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));

        candidates.into_iter().take(top_k as usize).collect()
    }
