}

fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    a.iter()
     .zip(b.iter())
     .map(|(x, y)| {
         let diff = x - y;
         (diff * diff) as f64
     })
     .sum()
}

#[cfg(any(target_arch = "x86", target_arch = "x86_64"))]
#[target_feature(enable = "avx2")]
unsafe fn l2_distance_avx2(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm256_setzero_ps();
    let n = a.len();
    let mut i = 0;

    // Process 8 elements at a time
    while i + 8 <= n {
        let va = _mm256_loadu_ps(a.as_ptr().add(i));
        let vb = _mm256_loadu_ps(b.as_ptr().add(i));
        let diff = _mm256_sub_ps(va, vb);
        let sq = _mm256_mul_ps(diff, diff);
        sum = _mm256_add_ps(sum, sq);
        i += 8;
    }

    // Horizontal sum
    // _mm256_hadd_ps adds adjacent pairs. We need to reduce to a single float.
    // Easier usually to just extract or do shuffling.
    // Let's use a temporary array to extract.
    let mut temp = [0.0f32; 8];
    _mm256_storeu_ps(temp.as_mut_ptr(), sum);
    let mut total = temp.iter().sum::<f32>() as f64;

    // Handle remaining elements
    while i < n {
        let diff = a[i] - b[i];
        total += (diff * diff) as f64;
        i += 1;
    }

    total
}

#[cfg(any(target_arch = "x86", target_arch = "x86_64"))]
#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm512_setzero_ps();
    let n = a.len();
    let mut i = 0;

    // Process 16 elements at a time
    while i + 16 <= n {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        // fmadd: a * b + c. We want diff * diff + sum
        sum = _mm512_fmadd_ps(diff, diff, sum);
        i += 16;
    }

    // Reduce sum
    let mut total = _mm512_reduce_add_ps(sum) as f64;

    // Handle remaining elements
    while i < n {
        let diff = a[i] - b[i];
        total += (diff * diff) as f64;
        i += 1;
    }

    total
}

use crate::api::*;
use std::sync::RwLock;

pub struct VectorDB {
    // SoA layout
    // We strictly assume 128 dimensions as per spec.
    // vectors: flatten storage. i-th vector is at vectors[i*128 .. (i+1)*128]
    data: RwLock<VectorStorage>,
}

struct VectorStorage {
    ids: Vec<u64>,
    vectors: Vec<f32>,
    count: usize,
}

const DIM: usize = 128;

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(VectorStorage {
                ids: Vec::new(),
                vectors: Vec::new(),
                count: 0,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != DIM {
            panic!("Vector dimension mismatch");
        }
        let mut data = self.data.write().unwrap();
        data.ids.push(id);
        data.vectors.extend(vector);
        data.count += 1;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = vectors.len();
        data.ids.reserve(count);
        data.vectors.reserve(count * DIM);

        for (id, vector) in vectors {
            if vector.len() != DIM {
                continue; // or panic
            }
            data.ids.push(id);
            data.vectors.extend(vector);
            data.count += 1;
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if vector.len() != DIM {
            return Vec::new();
        }

        let data = self.data.read().unwrap();
        let n = data.count;

        // Calculate all distances
        // We can iterate over chunks of the big vector
        let mut scores: Vec<(usize, f64)> = (0..n).into_iter()
            .map(|i| {
                let start = i * DIM;
                let end = start + DIM;
                let v = &data.vectors[start..end];
                let dist = crate::distance::l2_distance(v, vector);
                (i, dist)
            })
            .collect();

        // Select top k
        let k = top_k as usize;
        if k < scores.len() {
            scores.select_nth_unstable_by(k, |a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));
            scores.truncate(k);
        }

        // Sort the top k (needed for the API requirement "closest first")
        scores.sort_unstable_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));

        // Map back to IDs
        scores.into_iter().map(|(idx, dist)| {
            SearchResult {
                id: data.ids[idx],
                distance: dist,
            }
        }).collect()
    }
}

