        if vector.len() != DIM {
            return Vec::new();
        }

        let data = self.data.read().unwrap();
        let n = data.count;
        let k = top_k as usize;

        // We maintain a list of best candidates, sorted by distance ascending.
        // We only keep k elements.
        let mut best_candidates: Vec<SearchResult> = Vec::with_capacity(k + 1);

        let vectors = &data.vectors;
        let ids = &data.ids;

        // Unsafe pointer access for speed
        let vectors_ptr = vectors.as_ptr();

        for i in 0..n {
            // Compute distance
            let dist = unsafe {
                let p = vectors_ptr.add(i * DIM);
                crate::distance::l2_distance(std::slice::from_raw_parts(p, DIM), vector)
            };

            // Optimization: check if we should even consider inserting
            if best_candidates.len() < k {
                best_candidates.push(SearchResult { id: ids[i], distance: dist });
                // If full, sort to establish the order and strict cutoff
                if best_candidates.len() == k {
                    best_candidates.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));
                }
            } else {
                // We have k candidates. 
                // data.last() is the worst (largest distance) because we sort ascending.
                // If current dist is smaller than the worst, we insert it.
                if dist < best_candidates[k - 1].distance {
                    // Insert into sorted position
                    // Search for insertion point
                    let pos = best_candidates.partition_point(|x| x.distance <= dist);
                    best_candidates.insert(pos, SearchResult { id: ids[i], distance: dist });
                    best_candidates.pop(); // Remove the last (worst) one
                }
            }
