pub struct VectorDB {
    data: RwLock<VectorStorage>,
}

struct VectorStorage {
    ids: Vec<u64>,
    vectors: Vec<f32>,
    count: usize,
}

const DIM: usize = 128;

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(VectorStorage {
                ids: Vec::new(),
                vectors: Vec::new(),
                count: 0,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != DIM {
            panic!("Vector dimension mismatch");
        }
        let mut data = self.data.write().unwrap();
        data.ids.push(id);
        data.vectors.extend(vector);
        data.count += 1;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = vectors.len();
        data.ids.reserve(count);
        data.vectors.reserve(count * DIM);

        for (id, vector) in vectors {
            if vector.len() != DIM {
                continue; 
            }
            data.ids.push(id);
            data.vectors.extend(vector);
            data.count += 1;
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let k = top_k as usize;
        let data = self.data.read().unwrap();
        let n = data.count;
        if n == 0 {
            return Vec::new();
        }

        // We use a min-heap to keep the top-k BEST results.
        // Wait, "closest first" means smaller distance is better.
        // So we want to keep the k smallest distances.
        // A Max-Heap of size k allows us to track the k-th smallest element (the heap top).
        // Any new element smaller than heap.top() replaces it.
        // Rust's BinaryHeap is a max-heap.

        // We will store (Distance, Id).
        // BinaryHeap compares the first element.
        // We want to keep the K smallest distances.
        // The heap will store the K candidates encountered so far.
        // The top of the heap is the WORST candidate (largest distance) among the K best.
        // If a new candidate has smaller distance than heap.peek(), we pop and push.

        // But BinaryHeap is slow due to allocations/rebalancing on every push/pop.
        // With k=10, a simple sorted array or insertion sort is faster.
        // My previous implementation used sorted array with linear search for insertions.

        let mut candidates: Vec<SearchResult> = Vec::with_capacity(k + 1);

        let vectors_ptr = data.vectors.as_ptr();
        let ids = &data.ids;

        for i in 0..n {
            let dist = unsafe {
                // Manually inline? l2_distance_avx512 is hot.
                // The function call overhead is small but non-zero.
                crate::distance::l2_distance(std::slice::from_raw_parts(vectors_ptr.add(i * DIM), DIM), vector)
            };

            if candidates.len() < k {
                candidates.push(SearchResult { id: ids[i], distance: dist });
                if candidates.len() == k {
                    // Sort descending so the last element is the smallest distance?
                    // No, we want to maintain the best k. 
                    // Let's keep them sorted by distance ascending.
                    // The largest distance is at the end.
                    candidates.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));
                }
            } else {
                // Check against the worst (last) candidate
                if dist < candidates[k - 1].distance {
                     // Find insertion point. Bisection is better than linear scan for k=10? Maybe not.
                     // Linear scan from right to left is likely faster for small k.
                     // Actually, just find the index and insert.
                     let idx = candidates.partition_point(|x| x.distance <= dist);
                     candidates.insert(idx, SearchResult { id: ids[i], distance: dist });
                     candidates.truncate(k);
                }
            }
        }

        if candidates.len() < k {
            candidates.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));
        }

        candidates
    }
}

use crate::api::*;
use std::sync::RwLock;
use rand::Rng;
use rayon::prelude::*;

const DIM: usize = 128;
const MIN_Vectors_FOR_INDEX: usize = 10_000;
const K_FACTOR: usize = 40; // rough guess, N/K_FACTOR for centroid count? No, sqrt(N) is better.

pub struct VectorDB {
    storage: RwLock<Storage>,
}

enum Storage {
    Flat(FlatIndex),
    Ivf(IvfIndex),
}

struct FlatIndex {
    ids: Vec<u64>,
    vectors: Vec<f32>,
    count: usize,
}

struct IvfIndex {
    centroids: Vec<f32>,      // k * DIM
    lists: Vec<FlatIndex>,    // k lists
    num_centroids: usize,
    unindexed: FlatIndex,     // small buffer for new inserts
}

impl FlatIndex {
    fn new() -> Self {
        FlatIndex {
            ids: Vec::new(),
            vectors: Vec::new(),
            count: 0,
        }
    }

    fn push(&mut self, id: u64, vector: &[f32]) {
        self.ids.push(id);
        self.vectors.extend_from_slice(vector);
        self.count += 1;
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            storage: RwLock::new(Storage::Flat(FlatIndex::new())),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != DIM { return; }

        let mut storage = self.storage.write().unwrap();
        match &mut *storage {
            Storage::Flat(flat) => {
                flat.push(id, &vector);
            }
            Storage::Ivf(ivf) => {
                // Determine closest centroid
                let (closest_idx, _) = find_closest_centroid(&ivf.centroids, &vector);
                ivf.lists[closest_idx].push(id, &vector);
            }
        }
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut storage = self.storage.write().unwrap();
        let count = vectors.len();

        // Temporary buffer to hold data before we decide where it goes
        // Getting ownership of vectors is good.

        match &mut *storage {
            Storage::Flat(flat) => {
                for (id, vec) in vectors {
                    if vec.len() == DIM {
                        flat.push(id, &vec);
                    }
                }

                // Check if we should index
                if flat.count >= MIN_Vectors_FOR_INDEX {
                    // Upgrade to IVF
                    // Taking ownership of the data in flat
                    let old_ids = std::mem::take(&mut flat.ids);
                    let old_vecs = std::mem::take(&mut flat.vectors);

                    // Re-structure data for training
                    // We need a list of slices or just use the flat vectors
                    let num_vectors = old_ids.len();
                    let k = (num_vectors as f64).sqrt() as usize; 
                    // limit k? 1M -> 1000.

                    let new_ivf = build_ivf(old_ids, old_vecs, k);
                    *storage = Storage::Ivf(new_ivf);
                }
            }
            Storage::Ivf(ivf) => {
                // For bulk insert into IVF, we can parallelize the assignment
                // But we need to update the lists, which is mutable.
                // Simple way: sequentially insert.
                // Optimized way: pre-calculate assignments in parallel, then group.

                // Let's do sequential for now to be safe, or optimize if needed.
                // Given the benchmark phase is usually read-heavy, slow bulk insert is OK-ish,
                // but let's not be too slow.
                for (id, vec) in vectors {
                    if vec.len() == DIM {
                         let (closest_idx, _) = find_closest_centroid(&ivf.centroids, &vec);
                        ivf.lists[closest_idx].push(id, &vec);
                    }
                }
            }
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if vector.len() != DIM { return Vec::new(); }

        let storage = self.storage.read().unwrap();
        match &*storage {
            Storage::Flat(flat) => {
                search_flat(flat, vector, top_k)
            }
            Storage::Ivf(ivf) => {
                search_ivf(ivf, vector, top_k)
            }
        }
    }
}

fn search_flat(data: &FlatIndex, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
    // Same logic as before
    let n = data.count;
    let k = top_k as usize;
    let mut candidates: Vec<SearchResult> = Vec::with_capacity(k + 1);
    let vectors_ptr = data.vectors.as_ptr();
    let ids = &data.ids;

    for i in 0..n {
        let dist = unsafe {
             crate::distance::l2_distance(std::slice::from_raw_parts(vectors_ptr.add(i * DIM), DIM), vector)
        };

        if candidates.len() < k {
            candidates.push(SearchResult { id: ids[i], distance: dist });
            if candidates.len() == k {
                candidates.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));
            }
        } else {
            if dist < candidates[k - 1].distance {
                 let idx = candidates.partition_point(|x| x.distance <= dist);
                 candidates.insert(idx, SearchResult { id: ids[i], distance: dist });
                 candidates.truncate(k);
            }
        }
    }

    // Final sort to be sure
    if candidates.len() < k {
        candidates.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));
    }
    candidates
}

fn search_ivf(ivf: &IvfIndex, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
    let k = top_k as usize;
    // 1. Find closest centroids
    // We want 'nprobe' closest clusters.
    // Heuristic: nprobe = sqrt(num_centroids) or fixed. 
    // With 1000 centroids, let's try 15.
    let nprobe = 16;

    // Scan all centroids
    let mut centroid_dists: Vec<(usize, f64)> = Vec::with_capacity(ivf.num_centroids);
    let c_ptr = ivf.centroids.as_ptr();
    for i in 0..ivf.num_centroids {
         let dist = unsafe {
             crate::distance::l2_distance(std::slice::from_raw_parts(c_ptr.add(i * DIM), DIM), vector)
        };
        centroid_dists.push((i, dist));
    }

    // Pick top nprobe
    centroid_dists.select_nth_unstable_by(nprobe, |a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));

    // Now search locally in these clusters
    // We can reuse the same candidate logic
    let mut candidates: Vec<SearchResult> = Vec::with_capacity(k + 1);

    for (c_idx, _) in centroid_dists.iter().take(nprobe) {
        let list = &ivf.lists[*c_idx];
        let n = list.count;
        if n == 0 { continue; }

        let vectors_ptr = list.vectors.as_ptr();
        let ids = &list.ids;

        for i in 0..n {
            let dist = unsafe {
                 crate::distance::l2_distance(std::slice::from_raw_parts(vectors_ptr.add(i * DIM), DIM), vector)
            };

            // Standard maintain-top-k logic
            if candidates.len() < k {
                candidates.push(SearchResult { id: ids[i], distance: dist });
                if candidates.len() == k {
                    candidates.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));
                }
            } else {
                if dist < candidates[k - 1].distance {
                     let idx = candidates.partition_point(|x| x.distance <= dist);
                     candidates.insert(idx, SearchResult { id: ids[i], distance: dist });
                     candidates.truncate(k);
                }
            }
        }
    }

    // Also search unindexed buffer if any
    {
        let list = &ivf.unindexed;
        if list.count > 0 {
             let vectors_ptr = list.vectors.as_ptr();
             let ids = &list.ids;
             for i in 0..list.count {
                  let dist = unsafe {
                     crate::distance::l2_distance(std::slice::from_raw_parts(vectors_ptr.add(i * DIM), DIM), vector)
                  };
                  if candidates.len() < k {
                    candidates.push(SearchResult { id: ids[i], distance: dist });
                    if candidates.len() == k {
                        candidates.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));
                    }
                } else {
                    if dist < candidates[k - 1].distance {
                         let idx = candidates.partition_point(|x| x.distance <= dist);
                         candidates.insert(idx, SearchResult { id: ids[i], distance: dist });
                         candidates.truncate(k);
                    }
                }
             }
        }
    }

    if candidates.len() < k {
        candidates.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));
    }

    candidates
}

fn find_closest_centroid(centroids: &[f32], vector: &[f32]) -> (usize, f64) {
    let num_centroids = centroids.len() / DIM;
    let mut min_dist = f64::MAX;
    let mut min_idx = 0;

    let c_ptr = centroids.as_ptr();
    for i in 0..num_centroids {
         let dist = unsafe {
             crate::distance::l2_distance(std::slice::from_raw_parts(c_ptr.add(i * DIM), DIM), vector)
        };
        if dist < min_dist {
            min_dist = dist;
            min_idx = i;
        }
    }
    (min_idx, min_dist)
}

fn build_ivf(ids: Vec<u64>, vectors: Vec<f32>, k: usize) -> IvfIndex {
    let num_vectors = ids.len();

    // 1. Initialize centroids (random sample)
    let mut rng = rand::thread_rng();
    let mut centroids = Vec::with_capacity(k * DIM);
    for _ in 0..k {
        let idx = rng.gen_range(0..num_vectors);
        let start = idx * DIM;
        centroids.extend_from_slice(&vectors[start..start + DIM]);
    }

    // 2. K-means iterations
    // Use smaller iterations for speed. 3-5 is usually enough for coarse index.
    let iterations = 5;
    for _iter in 0..iterations {
        // Assign points to clusters
        // We need thread-local accumulators for computing new centroids

        // Parallel assignment
        // Create atomic or thread-local storage for cluster sums and counts
        // Since k is small (1000), we can just have each thread reduce to a k-sized accumulator

        // Using Rayon `fold` + `reduce`
        // Chunks of vectors
        let chunk_size = 1000; // process 1000 vectors at a time

        let (new_centroids_acc, counts) = (0..num_vectors)
            .into_par_iter()
            .chunks(chunk_size)
            .map(|chunk_indices| {
                let mut local_sums = vec![0.0f32; k * DIM];
                let mut local_counts = vec![0usize; k];

                for i in chunk_indices {
                    let v = &vectors[i * DIM..(i + 1) * DIM];
                    let (best_idx, _) = find_closest_centroid(&centroids, v);

                    local_counts[best_idx] += 1;
                    let sum_start = best_idx * DIM;
                    let sum_slice = &mut local_sums[sum_start..sum_start + DIM];
                    for j in 0..DIM {
                        sum_slice[j] += v[j];
                    }
                }
                (local_sums, local_counts)
            })
            .reduce(
                || (vec![0.0f32; k * DIM], vec![0usize; k]),
                |(mut sums_a, mut counts_a), (sums_b, counts_b)| {
                    // vector add
                    for i in 0..sums_a.len() {
                        sums_a[i] += sums_b[i];
                    }
                    for i in 0..counts_a.len() {
                        counts_a[i] += counts_b[i];
                    }
                    (sums_a, counts_a)
                }
            );

        // Update centroids
        let mut max_move = 0.0;
        for i in 0..k {
            let count = counts[i];
            if count > 0 {
                let start = i * DIM;
                for j in 0..DIM {
                    let new_val = new_centroids_acc[start + j] / count as f32;
                    // centroids[start + j] = new_val; // We can check convergence if we want
                     centroids[start + j] = new_val;
                }
            } else {
                // Re-initialize empty cluster?
                // Pick a random vector again? 
                // Ignore for now.
            }
        }
    }

    // 3. Final assignment and partitioning
    // Create the lists
    let mut lists: Vec<FlatIndex> = (0..k).map(|_| FlatIndex::new()).collect();

    // We can't trivially parallelize pushing to lists without locks.
    // But we can compute assignments in parallel: `Vec<usize>` (cluster_id for each vector)
    // Then shuffle data.

    let assignments: Vec<usize> = (0..num_vectors)
        .into_par_iter()
        .map(|i| {
            let v = &vectors[i * DIM..(i + 1) * DIM];
            let (best_idx, _) = find_closest_centroid(&centroids, v);
            best_idx
        })
        .collect();

    // Now single-threaded partitioning (memory bandwidth bound mostly)
    for (i, &cluster_idx) in assignments.iter().enumerate() {
        let v = &vectors[i * DIM..(i + 1) * DIM];
        lists[cluster_idx].push(ids[i], v);
    }

    IvfIndex {
        centroids,
        lists,
        num_centroids: k,
        unindexed: FlatIndex::new(),
    }
}

#[cfg(any(target_arch = "x86", target_arch = "x86_64"))]
use std::arch::x86_64::*;

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    #[cfg(any(target_arch = "x86", target_arch = "x86_64"))]
    {
        if is_x86_feature_detected!("avx512f") {
            return unsafe { l2_distance_avx512(a, b) };
        } else if is_x86_feature_detected!("avx2") {
            return unsafe { l2_distance_avx2(a, b) };
        }
    }
    l2_distance_scalar(a, b)
}

fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    a.iter()
     .zip(b.iter())
     .map(|(x, y)| {
         let diff = x - y;
         (diff * diff) as f64
     })
     .sum()
}

#[cfg(any(target_arch = "x86", target_arch = "x86_64"))]
#[target_feature(enable = "avx2")]
unsafe fn l2_distance_avx2(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm256_setzero_ps();
    let n = a.len();
    if n == 128 {
        let ptr_a = a.as_ptr();
        let ptr_b = b.as_ptr();
        // 128 / 8 = 16 iterations
        for i in 0..16 {
            let va = _mm256_loadu_ps(ptr_a.add(i*8));
            let vb = _mm256_loadu_ps(ptr_b.add(i*8));
            let diff = _mm256_sub_ps(va, vb);
            let sq = _mm256_mul_ps(diff, diff);
            sum = _mm256_add_ps(sum, sq);
        }
        let mut temp = [0.0f32; 8];
        _mm256_storeu_ps(temp.as_mut_ptr(), sum);
        return temp.iter().sum::<f32>() as f64;
    }

    let mut i = 0;
    while i + 8 <= n {
        let va = _mm256_loadu_ps(a.as_ptr().add(i));
        let vb = _mm256_loadu_ps(b.as_ptr().add(i));
        let diff = _mm256_sub_ps(va, vb);
        let sq = _mm256_mul_ps(diff, diff);
        sum = _mm256_add_ps(sum, sq);
        i += 8;
    }

    let mut temp = [0.0f32; 8];
    _mm256_storeu_ps(temp.as_mut_ptr(), sum);
    let mut total = temp.iter().sum::<f32>() as f64;

    while i < n {
        let diff = a[i] - b[i];
        total += (diff * diff) as f64;
        i += 1;
    }
    total
}

#[cfg(any(target_arch = "x86", target_arch = "x86_64"))]
#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    // Optimized for 128 dim
    if a.len() == 128 {
        let ptr_a = a.as_ptr();
        let ptr_b = b.as_ptr();

        let mut sum0 = _mm512_setzero_ps();
        let mut sum1 = _mm512_setzero_ps();
        let mut sum2 = _mm512_setzero_ps();
        let mut sum3 = _mm512_setzero_ps();

        // Unroll 4x (4 * 16 = 64 floats)
        // 128 floats = 2 passes of 4x unroll, or just 1 pass of 8x unroll.
        // Let's do 8x unroll directly since registers are plenty (zmm0-31).

        // Group 0
        let va0 = _mm512_loadu_ps(ptr_a);
        let vb0 = _mm512_loadu_ps(ptr_b);
        let diff0 = _mm512_sub_ps(va0, vb0);
        sum0 = _mm512_fmadd_ps(diff0, diff0, sum0);

        let va1 = _mm512_loadu_ps(ptr_a.add(16));
        let vb1 = _mm512_loadu_ps(ptr_b.add(16));
        let diff1 = _mm512_sub_ps(va1, vb1);
        sum1 = _mm512_fmadd_ps(diff1, diff1, sum1);

        let va2 = _mm512_loadu_ps(ptr_a.add(32));
        let vb2 = _mm512_loadu_ps(ptr_b.add(32));
        let diff2 = _mm512_sub_ps(va2, vb2);
        sum2 = _mm512_fmadd_ps(diff2, diff2, sum2);

        let va3 = _mm512_loadu_ps(ptr_a.add(48));
        let vb3 = _mm512_loadu_ps(ptr_b.add(48));
        let diff3 = _mm512_sub_ps(va3, vb3);
        sum3 = _mm512_fmadd_ps(diff3, diff3, sum3);

        let va4 = _mm512_loadu_ps(ptr_a.add(64));
        let vb4 = _mm512_loadu_ps(ptr_b.add(64));
        let diff4 = _mm512_sub_ps(va4, vb4);
        sum0 = _mm512_fmadd_ps(diff4, diff4, sum0);

        let va5 = _mm512_loadu_ps(ptr_a.add(80));
        let vb5 = _mm512_loadu_ps(ptr_b.add(80));
        let diff5 = _mm512_sub_ps(va5, vb5);
        sum1 = _mm512_fmadd_ps(diff5, diff5, sum1);

        let va6 = _mm512_loadu_ps(ptr_a.add(96));
        let vb6 = _mm512_loadu_ps(ptr_b.add(96));
        let diff6 = _mm512_sub_ps(va6, vb6);
        sum2 = _mm512_fmadd_ps(diff6, diff6, sum2);

        let va7 = _mm512_loadu_ps(ptr_a.add(112));
        let vb7 = _mm512_loadu_ps(ptr_b.add(112));
        let diff7 = _mm512_sub_ps(va7, vb7);
        sum3 = _mm512_fmadd_ps(diff7, diff7, sum3);

        // Sum up accumulators
        let sum01 = _mm512_add_ps(sum0, sum1);
        let sum23 = _mm512_add_ps(sum2, sum3);
        let sum = _mm512_add_ps(sum01, sum23);

        return _mm512_reduce_add_ps(sum) as f64;
    }

    let mut sum = _mm512_setzero_ps();
    let n = a.len();
    let mut i = 0;

    while i + 16 <= n {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        sum = _mm512_fmadd_ps(diff, diff, sum);
        i += 16;
    }

    let mut total = _mm512_reduce_add_ps(sum) as f64;

    while i < n {
        let diff = a[i] - b[i];
        total += (diff * diff) as f64;
        i += 1;
    }

    total
}

