    let vb = _mm512_loadu_ps(ptr_b.add(16));
    let diff = _mm512_sub_ps(va, vb);
    sum1 = _mm512_fmadd_ps(diff, diff, sum1);

    // 2
    let va = _mm512_loadu_ps(ptr_a.add(32));
    let vb = _mm512_loadu_ps(ptr_b.add(32));
    let diff = _mm512_sub_ps(va, vb);
    sum2 = _mm512_fmadd_ps(diff, diff, sum2);

    // 3
    let va = _mm512_loadu_ps(ptr_a.add(48));
    let vb = _mm512_loadu_ps(ptr_b.add(48));
    let diff = _mm512_sub_ps(va, vb);
    sum3 = _mm512_fmadd_ps(diff, diff, sum3);

    // 4
    let va = _mm512_loadu_ps(ptr_a.add(64));
    let vb = _mm512_loadu_ps(ptr_b.add(64));
    let diff = _mm512_sub_ps(va, vb);
    sum0 = _mm512_fmadd_ps(diff, diff, sum0);

    // 5
    let va = _mm512_loadu_ps(ptr_a.add(80));
    let vb = _mm512_loadu_ps(ptr_b.add(80));
    let diff = _mm512_sub_ps(va, vb);
    sum1 = _mm512_fmadd_ps(diff, diff, sum1);

    // 6
    let va = _mm512_loadu_ps(ptr_a.add(96));
    let vb = _mm512_loadu_ps(ptr_b.add(96));
    let diff = _mm512_sub_ps(va, vb);
