    let diff = _mm512_sub_ps(va, vb);
    sum3 = _mm512_fmadd_ps(diff, diff, sum3);

    // Reduce
    let sum01 = _mm512_add_ps(sum0, sum1);
    let sum23 = _mm512_add_ps(sum2, sum3);
    let sum_final = _mm512_add_ps(sum01, sum23);

    _mm512_reduce_add_ps(sum_final) as f64
}

